from dataclasses import dataclass, field
from enum import Enum

class PermissionLevel(str, Enum):
    READ = "read"
    WRITE = "write"
    DESTRUCTIVE = "destructive"
    ELEVATED = "elevated"

@dataclass
class ToolPermission:
    tool_name: str
    level: PermissionLevel
    requires_confirmation: bool = False

@dataclass
class AgentPermissionPolicy:
    """
    Defines which tools an agent may call and at what level.
    Pass this into the tool dispatcher — never into the agent's system prompt.
    """
    agent_id: str
    allowed: list[ToolPermission] = field(default_factory=list)

    def _get(self, tool_name: str) -> ToolPermission | None:
        for perm in self.allowed:
            if perm.tool_name == tool_name:
                return perm
        return None

    def can_call(self, tool_name: str) -> bool:
        return self._get(tool_name) is not None

    def requires_confirmation(self, tool_name: str) -> bool:
        perm = self._get(tool_name)
        return perm.requires_confirmation if perm else False

    def assert_allowed(self, tool_name: str):
        if not self.can_call(tool_name):
            raise PermissionError(
                f"Agent '{self.agent_id}' is not allowed to call tool '{tool_name}'"
            )

# Policy for a read-only research agent:
research_policy = AgentPermissionPolicy(
    agent_id="researcher",
    allowed=[
        ToolPermission("web_search", PermissionLevel.READ),
        ToolPermission("read_file", PermissionLevel.READ),
        ToolPermission("query_database", PermissionLevel.READ),
    ],
)

# Policy for an assistant that may draft and send emails:
email_policy = AgentPermissionPolicy(
    agent_id="email-assistant",
    allowed=[
        ToolPermission("read_email", PermissionLevel.READ),
        ToolPermission("create_draft", PermissionLevel.WRITE),
        ToolPermission("send_email", PermissionLevel.DESTRUCTIVE, requires_confirmation=True),
    ],
)

# Enforcement
research_policy.assert_allowed("web_search")    # OK
try:
    research_policy.assert_allowed("send_email")  # raises PermissionError
except PermissionError as e:
    print(e)  # Agent 'researcher' is not allowed to call tool 'send_email'

import anthropic
import json

client = anthropic.Anthropic()

# --- Tool implementations ---
def web_search(query: str) -> str:
    return f"(search results for: {query})"

def send_email(to: str, subject: str, body: str) -> str:
    return f"Email sent to {to}"

TOOL_IMPL = {
    "web_search": lambda inp: web_search(inp["query"]),
    "send_email": lambda inp: send_email(inp["to"], inp["subject"], inp["body"]),
}

TOOLS = [
    {
        "name": "web_search",
        "description": "Search the web for information.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
    {
        "name": "send_email",
        "description": "Send an email.",
        "input_schema": {
            "type": "object",
            "properties": {
                "to": {"type": "string"},
                "subject": {"type": "string"},
                "body": {"type": "string"},
            },
            "required": ["to", "subject", "body"],
        },
    },
]

def run_agent_with_policy(task: str, policy: AgentPermissionPolicy) -> str:
    """Run an agent loop that enforces the given permission policy."""
    messages = [{"role": "user", "content": task}]
    while True:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            tools=TOOLS,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next((b.text for b in resp.content if hasattr(b, "text")), "")

        messages.append({"role": "assistant", "content": resp.content})
        tool_results = []
        for block in resp.content:
            if block.type != "tool_use":
                continue
            try:
                policy.assert_allowed(block.name)
                output = TOOL_IMPL[block.name](block.input)
            except PermissionError as e:
                output = f"Permission denied: {e}"
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": output,
            })
        messages.append({"role": "user", "content": tool_results})

# Research agent: may search, may not send email
result = run_agent_with_policy(
    "Search for LLM safety papers and then email a summary to alice@example.com.",
    policy=research_policy,
)
print(result)
# The agent will find that send_email is blocked and report it cannot send the email.

def dispatch_with_confirmation(
    block,
    policy: AgentPermissionPolicy,
    confirm_fn=None,
) -> str:
    """
    Dispatch a tool call, pausing for user confirmation on destructive tools.
    confirm_fn: callable(tool_name, inputs) -> bool.
    If None, defaults to a CLI prompt.
    """
    policy.assert_allowed(block.name)

    if policy.requires_confirmation(block.name):
        if confirm_fn is None:
            answer = input(
                f"Agent wants to call '{block.name}' with inputs:\n"
                f"{json.dumps(block.input, indent=2)}\n"
                f"Allow? [y/N] "
            ).strip().lower()
            if answer != "y":
                return "User denied this action."
        elif not confirm_fn(block.name, block.input):
            return "User denied this action."

    return TOOL_IMPL[block.name](block.input)

