from pathlib import Path

@dataclass
class ScopedPermission:
    tool_name: str
    level: PermissionLevel
    # Optional: resource ID allowlist (None = any resource allowed)
    allowed_resource_ids: list[str] | None = None
    requires_confirmation: bool = False

@dataclass
class ScopedPolicy:
    agent_id: str
    allowed: list[ScopedPermission] = field(default_factory=list)

    def check(self, tool_name: str, resource_id: str | None = None):
        for perm in self.allowed:
            if perm.tool_name != tool_name:
                continue
            if perm.allowed_resource_ids is not None and resource_id not in perm.allowed_resource_ids:
                raise PermissionError(
                    f"Agent '{self.agent_id}' may not access resource '{resource_id}' via '{tool_name}'"
                )
            return perm
        raise PermissionError(
            f"Agent '{self.agent_id}' is not allowed to call tool '{tool_name}'"
        )

# Agent that can read files only from /reports/ directory:
report_agent_policy = ScopedPolicy(
    agent_id="report-reader",
    allowed=[
        ScopedPermission(
            "read_file",
            PermissionLevel.READ,
            allowed_resource_ids=["/reports/q1.pdf", "/reports/q2.pdf"],
        ),
    ],
)

# At dispatch time, pass the resource being accessed:
try:
    report_agent_policy.check("read_file", resource_id="/reports/q1.pdf")
    print("Access granted")
except PermissionError as e:
    print(e)

try:
    report_agent_policy.check("read_file", resource_id="/etc/shadow")
except PermissionError as e:
    print(e)
    # Agent 'report-reader' may not access resource '/etc/shadow' via 'read_file'
